// src/components/common/ContactForm.tsx
'use client';

import React, { useState } from 'react';
import { Button } from '@/components/ui/Button'; // Import the reusable Button component

interface FormField {
  name: string;
  type: 'text' | 'email' | 'tel' | 'number' | 'textarea';
  placeholder: string;
  required: boolean;
  options?: { value: string; label: string }[]; // For select/dropdown if needed in future
}

interface ContactFormProps {
  fields: FormField[];
  submissionEndpoint: string;
}

const ContactForm: React.FC<ContactFormProps> = ({ fields, submissionEndpoint }) => {
  const [status, setStatus] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setIsSubmitting(true);
    setStatus(null);

    const form = event.currentTarget;
    const data = new FormData(form);

    try {
      const response = await fetch(submissionEndpoint, {
        method: 'POST',
        body: data,
        headers: {
          'Accept': 'application/json',
        },
      });

      if (response.ok) {
        form.reset();
        setStatus('Thank you! Your enquiry has been sent.');
      } else {
        const errorData = await response.json();
        if (errorData && errorData.errors) {
          setStatus(errorData.errors.map((error: any) => error.message).join(', '));
        } else {
          setStatus('Oops! There was a problem submitting your form');
        }
      }
    } catch (error) {
      console.error('Form submission error:', error);
      setStatus('Oops! There was a problem submitting your form');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {fields.map((field) => (
        <div key={field.name} className="form-group">
          {field.type === 'textarea' ? (
            <textarea
              className="form-control w-full p-2 text-base border border-gray-300 rounded-md"
              name={field.name}
              placeholder={field.placeholder}
              required={field.required}
              disabled={isSubmitting}
              rows={3}
            ></textarea>
          ) : (
            <input
              type={field.type}
              className="form-control w-full p-2 text-base border border-gray-300 rounded-md"
              name={field.name}
              placeholder={field.placeholder}
              required={field.required}
              disabled={isSubmitting}
            />
          )}
        </div>
      ))}
      <Button
        type="submit"
        variant="fill"
        size="default"
        className="w-full mt-3"
        disabled={isSubmitting}
      >
        {isSubmitting ? 'Sending...' : 'Submit'}
      </Button>
      {status && (
        <p className={`mt-3 text-center ${status.includes('Thank you') ? 'text-green-500' : 'text-red-500'}`}>
          {status}
        </p>
      )}
    </form>
  );
};

export default ContactForm;